script:
frappe.ui.form.on('Gerenciamiento de viajes', {
	refresh(frm) {
		// your code here
	},
	conductor(frm){
        frm.set_value('departamento_de_conductor', "");
	    if (frm.doc.empleado_conductor){
            frappe.call({
                method: 'obtener_empleado_por_conductor',
                args: {
                    name: frm.doc.empleado_conductor
                },
                callback: function(r) {
                    if (r.message) {
                        console.log(1231231,r.message)
                        frm.set_value('departamento_de_conductor', r.message.jefe_department);
                    }
                }
            });
	    }
	},
	autorizador(frm){
        frm.set_value('no_de_emergencia', "");
        console.log(frm.doc.número_de_empleado_de_autorizador)
	    if (frm.doc.número_de_empleado_de_autorizador){
            frappe.call({
                method: 'obtener_empleado_por_conductor',
                args: {
                    name: frm.doc.número_de_empleado_de_autorizador
                },
                callback: function(r) {
                    if (r.message) {
                        console.log(111,r.message)
                        frm.set_value('no_de_emergencia', r.message.emergency_phone_number);
                    }
                }
            });
	    }
	}
})
